The XDR patch that I gave out only touches the 64bit routines in the
XDR library, so here is the XDR library before my patch:

/*
 * XDR 64-bit integers
 */
bool_t
xdr_int64_t(xdrs, int64_p)
        register XDR *xdrs;
        int64_t *int64_p;
{
        int64_t x;

        switch (xdrs->x_op) {

        case XDR_ENCODE:
                return (xdr_opaque(xdrs, (caddr_t)int64_p, sizeof(int64_t)));

        case XDR_DECODE:
                if (!xdr_opaque(xdrs, (caddr_t)&x, sizeof x)) {
                        return (FALSE);
                }
                *int64_p = x;
                return (TRUE);

        case XDR_FREE:
                return (TRUE);
        }
        return (FALSE);
}

/*
 * XDR unsigned 64-bit integers
 */
bool_t
xdr_u_int64_t(xdrs, uint64_p)
        register XDR *xdrs;
        u_int64_t *uint64_p;
{
        u_int64_t x;

        switch (xdrs->x_op) {

        case XDR_ENCODE:
                return (xdr_opaque(xdrs, (caddr_t)uint64_p, sizeof(u_int64_t)));

        case XDR_DECODE:
                if (!xdr_opaque(xdrs, (caddr_t)&x, sizeof x)) {
                        return (FALSE);
                }
                *uint64_p = x;
                return (TRUE);

        case XDR_FREE:
                return (TRUE);
        }
        return (FALSE);
}


